import { Link, Navigate, Route, Routes, useNavigate } from "react-router-dom";
import "./dashboard.css";

function HomeSection() {
  return (
    <section className="hero-section">
      <div className="hero-copy">
        <p className="welcome-line">
          Welcome <span>Aditya</span> to My Portfolio
        </p>
        <h1>
          Hello, I&apos;m
          <br />
          Prathmesh Nalawade
        </h1>
        <p className="tagline">
          BSC Graduate | MERN Stack (Fresher) |
          <br />
          React.js • Node.js • Express.js • MongoDB |
          <br />
          Bootstrap | Tailwind | Docker
        </p>
      </div>
      <div className="hero-image-wrap" aria-hidden="true">
        <div className="hero-image" />
      </div>
    </section>
  );
}

function SectionPage({ title, text }) {
  return (
    <section className="section-page">
      <h2>{title}</h2>
      <p>{text}</p>
    </section>
  );
}

function Dashboard() {
  const navigate = useNavigate();

  const logout = () => {
    localStorage.removeItem("token");
    navigate("/");
  };

  return (
    <main className="dashboard-wrap">
      <header className="dashboard-nav">
        <Link to="/dashboard/home" className="brand">
          MyPortfolio
        </Link>
        <nav>
          <Link to="/dashboard/about">About</Link>
          <Link to="/dashboard/skills">Skills</Link>
          <Link to="/dashboard/projects">Projects</Link>
          <Link to="/dashboard/contact">Contact</Link>
          <button type="button" onClick={logout} className="logout-btn">
            Logout
          </button>
        </nav>
      </header>

      <Routes>
        <Route path="/" element={<Navigate to="home" replace />} />
        <Route path="home" element={<HomeSection />} />
        <Route path="about" />
        <Route path="skills" />
        <Route path="projects" />
        <Route path="contact" />
        <Route path="*" element={<Navigate to="home" replace />} />
      </Routes>
    </main>
  );
}

export default Dashboard;
